func:
node.warn('[ingest] Watch event: type=' + msg.event + ' file=' + msg.payload + ' filename=' + msg.filename);
msg.topic = msg.filename;
return msg;

node.warn('[ingest] Preparing MinIO upload: ' + (msg.filename || msg.payload));
const filePath = msg.filename || msg.payload;
const fileName = (filePath || '').split('/').pop();
const ext = (fileName || '').split('.').pop().toLowerCase();
const ts = new Date().toISOString().replace(/[:.]/g, '-');
const prefix = env.get('MINIO_PREFIX') || 'recordings';
const objectKey = `${prefix}/${ts}-${fileName}`;

const mimeMap = {
  mp3: 'audio/mpeg',
  wav: 'audio/wav',
  m4a: 'audio/mp4',
  ogg: 'audio/ogg',
  mp4: 'video/mp4',
  mov: 'video/quicktime',
  mkv: 'video/x-matroska'
};

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

msg.meta = {
  filePath,
  fileName,
  ext,
  mime: mimeMap[ext] || 'application/octet-stream',
  objectKey,
  eventId: uuidv4()
};

msg.execArgs = `"${filePath}" "${objectKey}"`;
return msg;

node.warn('[ingest] Building upload envelope, presign url: ' + ((msg.payload || {}).url || 'MISSING'));
const meta = msg.meta || {};
const presign = msg.payload || {};
const homeDir = env.get('HOME') || '/home/delorenj';

const envelope = {
  event_type: 'fireflies.transcript.upload',
  event_id: meta.eventId,
  timestamp: new Date().toISOString(),
  version: '1.0.0',
  source: {
    host: 'node-red',
    type: 'file_watch',
    app: 'node-red'
  },
  correlation_ids: [],
  payload: {
    media_file: presign.url,
    media_duration_seconds: 0,
    media_type: presign.content_type || meta.mime,
    title: meta.fileName,
    user_id: null,
    created_at: new Date().toISOString(),
    content_hash: meta.contentHash,
    minio_bucket: presign.bucket || (env.get('MINIO_BUCKET') || 'echobox'),
    minio_key: meta.objectKey || '',
    minio_url: presign.url || ''
  }
};

const outPath = `${homeDir}/.node-red/bb/fireflies-upload-${meta.eventId}.json`;
msg.envelope = envelope;
msg.payload = JSON.stringify(envelope);
msg.filename = outPath;
msg.curlData = '@' + outPath;
node.warn('[ingest] Envelope built with content_hash=' + (meta.contentHash || 'MISSING').slice(0,12) + ', writing to: ' + outPath);
return msg;

var buf = context.get('_buf') || '';
buf += msg.payload;
var lines = buf.split('\n');
var remainder = lines.pop();
for (var i = 0; i < lines.length; i++) {
    var line = lines[i].trim();
    if (line.length === 0) continue;
    try {
        var parsed = JSON.parse(line);
        node.send({payload: parsed});
    } catch(e) {
        remainder = line + '\n' + remainder;
    }
}
context.set('_buf', remainder);
return null;

node.warn('[consume-upload] Received upload event: ' + ((msg.payload || {}).event_id || 'unknown'));
const envelope = msg.payload || {};
const payload = envelope.payload || {};
const webhook = env.get('FIREFLIES_WEBHOOK_URL') || '';

// Preserve content_hash and envelope for downstream ledger updates
const contentHash = payload.content_hash || null;
msg._contentHash = contentHash;
msg._originalEnvelope = envelope;

msg.headers = {
  'content-type': 'application/json',
  'authorization': `Bearer ${env.get('FIREFLIES_API_KEY') || ''}`
};

// Use content_hash as client_reference_id so the webhook can identify the job
msg.payload = {
  query: 'mutation($input: AudioUploadInput) { uploadAudio(input: $input) { success title message } }',
  variables: {
    input: {
      url: payload.media_file,
      title: payload.title || 'Recording',
      webhook: webhook || undefined,
      client_reference_id: contentHash || envelope.event_id
    }
  }
};
return msg;

// Debounce progressive Fireflies webhooks — only process the last one per upload
const payload = msg.payload || {};
const meetingId = payload.meetingId || payload.meeting_id;
const clientRef = payload.clientReferenceId || payload.client_reference_id || payload.clientReferenceID;

if (!meetingId) {
  node.error('Missing meetingId in webhook payload', msg);
  return null;
}

node.warn('[webhook] Fireflies webhook: meetingId=' + meetingId + ' clientRef=' + (clientRef || 'none'));

// clientRef is now the content_hash (set in consume-upload tab)
const contentHash = clientRef || null;

// Use clientRef as debounce key; fall back to meetingId if no clientRef
const debounceKey = clientRef || meetingId;
const DEBOUNCE_MS = 120000; // 2 minutes

const timers = flow.get('_webhook_timers') || {};
const pending = flow.get('_webhook_pending') || {};

if (timers[debounceKey]) {
  clearTimeout(timers[debounceKey]);
  node.warn('[webhook] Debounce reset for ' + debounceKey + ', newer webhook arrived');
}

pending[debounceKey] = { meetingId, clientRef, contentHash, receivedAt: Date.now() };
flow.set('_webhook_pending', pending);

const timer = setTimeout(() => {
  const p = flow.get('_webhook_pending') || {};
  const entry = p[debounceKey];
  if (!entry) return;

  delete p[debounceKey];
  flow.set('_webhook_pending', p);
  const t = flow.get('_webhook_timers') || {};
  delete t[debounceKey];
  flow.set('_webhook_timers', t);

  node.warn('[webhook] Debounce complete for ' + debounceKey + ', fetching transcript: ' + entry.meetingId);

  const outMsg = {
    meta: { clientRef: entry.clientRef, contentHash: entry.contentHash },
    headers: {
      'content-type': 'application/json',
      'authorization': 'Bearer ' + (env.get('FIREFLIES_API_KEY') || '')
    },
    payload: {
      query: `query Transcript($transcriptId: String!) {
        transcript(id: $transcriptId) {
          id title date dateString duration
          transcript_url audio_url video_url
          host_email organizer_email privacy
          meeting_link calendar_id calendar_type
          participants
          speakers { name }
          sentences {
            index speaker_name speaker_id text raw_text
            start_time end_time
            ai_filters { task pricing metric question date_and_time text_cleanup sentiment }
          }
          user { user_id email name num_transcripts minutes_consumed is_admin }
          meeting_attendees { displayName email }
          summary { overview short_summary }
          meeting_info { fred_joined silent_meeting summary_status }
        }
      }`,
      variables: { transcriptId: entry.meetingId }
    }
  };
  node.send(outMsg);
}, DEBOUNCE_MS);

timers[debounceKey] = timer;
flow.set('_webhook_timers', timers);

return null;

node.warn('[webhook] Transcript API response status: ' + (msg.statusCode || 'unknown'));
const response = msg.payload || {};
const transcript = response.data && response.data.transcript;
if (!transcript) {
  node.error('Transcript not found in response', msg);
  return null;
}

const meta = msg.meta || {};
const contentHash = meta.contentHash || null;
const correlation = [];
if (meta.clientRef) correlation.push(meta.clientRef);
if (contentHash && contentHash !== meta.clientRef) correlation.push(contentHash);
const homeDir = env.get('HOME') || '/home/delorenj';

const participants = (transcript.meeting_attendees || []).map(p => ({
  name: p.displayName || p.name || 'Unknown',
  email: p.email || null
}));
const speakers = (transcript.speakers || []).map(s => s.name).filter(Boolean);
const summaryText = (transcript.summary && (transcript.summary.overview || transcript.summary.short_summary)) || null;

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const envelope = {
  event_type: 'fireflies.transcript.ready',
  event_id: uuidv4(),
  timestamp: new Date().toISOString(),
  version: '1.0.0',
  source: {
    host: 'node-red',
    type: 'hook',
    app: 'node-red'
  },
  correlation_ids: correlation,
  payload: {
    id: transcript.id,
    title: transcript.title,
    date: transcript.date,
    duration: transcript.duration,
    transcript_url: transcript.transcript_url,
    audio_url: transcript.audio_url,
    video_url: transcript.video_url,
    sentences: transcript.sentences || [],
    summary: summaryText,
    participants: participants,
    speakers: speakers,
    user: transcript.user || {},
    host_email: transcript.host_email,
    organizer_email: transcript.organizer_email,
    privacy: transcript.privacy,
    meeting_link: transcript.meeting_link || null,
    calendar_id: transcript.calendar_id || null,
    calendar_type: transcript.calendar_type || null,
    raw_meeting_info: transcript.meeting_info || null,
    content_hash: contentHash
  }
};

const outPath = `${homeDir}/.node-red/bb/fireflies-ready-${envelope.event_id}.json`;
msg.envelope = envelope;
msg.payload = JSON.stringify(envelope);
msg.filename = outPath;
msg.curlData = '@' + outPath;
node.warn('[webhook] Ready envelope built with content_hash=' + (contentHash || 'MISSING') + ', writing to: ' + outPath);
return msg;

// Buffer chunks from spawn stdout until we have complete JSON lines
var buf = context.get('_buf') || '';
buf += msg.payload;

// Try to extract complete JSON objects from the buffer
var lines = buf.split('\n');
// Keep the last fragment (may be incomplete)
var remainder = lines.pop();

for (var i = 0; i < lines.length; i++) {
    var line = lines[i].trim();
    if (line.length === 0) continue;
    try {
        var parsed = JSON.parse(line);
        node.send({payload: parsed});
    } catch(e) {
        // Not valid JSON yet - prepend back to remainder
        remainder = line + '\n' + remainder;
    }
}

context.set('_buf', remainder);
return null;

node.warn('[consume-ready] Building outputs for: ' + ((msg.payload || {}).event_type || 'unknown') + ' id=' + ((msg.payload || {}).event_id || 'unknown'));
const envelope = msg.payload || {};
const transcript = envelope.payload || {};
const contentHash = transcript.content_hash || null;

const safe = (transcript.title || transcript.id || 'transcript')
  .toString().replace(/[^a-z0-9-_]+/gi, '_').slice(0, 80);
const baseDir = env.get('TRANSCRIPT_DIR') || '/home/delorenj/d/Transcripts';
const basePath = `${baseDir}/${safe}-${transcript.id}`;

const sentences = transcript.sentences || [];
const csvRows = sentences.map(s => ({
  index: s.index,
  speaker: s.speaker_name || s.speaker_id,
  start_time: s.start_time,
  end_time: s.end_time,
  text: s.text
}));

const summaryText = transcript.summary || '';
const mdLines = [
  `# ${transcript.title || transcript.id}`,
  '',
  transcript.date ? `Date: ${transcript.date}` : '',
  transcript.duration ? `Duration (min): ${transcript.duration}` : '',
  transcript.transcript_url ? `Transcript: ${transcript.transcript_url}` : '',
  '',
  summaryText ? '## Summary' : '',
  summaryText || '',
  '',
  '## Transcript',
  ...sentences.map(s => `- **${s.speaker_name || s.speaker_id}**: ${s.text}`)
].filter(Boolean);
const mdContent = mdLines.join('\n');

const msgCsv = { payload: csvRows, filename: `${basePath}.csv` };
const msgMd = { payload: mdContent, filename: `${basePath}.md` };

// Third output: ledger completion update using content_hash
const ledgerMsg = {
  headers: { 'content-type': 'application/json' },
  payload: {
    status: 'completed',
    transcript_path: msgMd.filename,
    csv_path: msgCsv.filename,
    fireflies_id: transcript.id
  }
};

if (contentHash) {
  ledgerMsg.url = 'http://localhost:18697/jobs/' + encodeURIComponent(contentHash);
} else {
  node.warn('[consume-ready] No content_hash in ready envelope, ledger update will be skipped');
  ledgerMsg.url = 'http://localhost:18697/jobs/unknown';
}

return [msgCsv, msgMd, ledgerMsg];

msg.meta = msg.meta || {};
msg.meta.filePath = msg.meta.filePath;
msg.meta.fileName = msg.meta.fileName;
msg.meta.objectKey = msg.meta.objectKey;
msg.meta.mime = msg.meta.mime;
msg.meta.eventId = msg.meta.eventId;
msg.payload = '"' + msg.meta.filePath + '"';
return msg;

const stdout = (msg.payload || '').trim();
const hash = stdout.split(/\s+/)[0];
if (!hash || hash.length !== 64) {
  node.error('Invalid SHA256: ' + stdout, msg);
  return null;
}
msg.meta = msg.meta || {};
msg.meta.contentHash = hash;

// Prepare ledger dedup check
msg.headers = { 'content-type': 'application/json' };
msg.payload = { content_hash: hash };
return msg;

const resp = msg.payload || {};
if (resp.exists && resp.job && resp.job.status === 'completed') {
  node.warn('[ingest] Dedup: already completed, skipping ' + msg.meta.contentHash.slice(0,12));
  return null;
}
if (resp.exists && resp.job) {
  node.warn('[ingest] Dedup: exists but status=' + resp.job.status + ', re-processing');
}
// Continue to create/update ledger job then upload
const meta = msg.meta || {};
msg.headers = { 'content-type': 'application/json' };
msg.payload = {
  content_hash: meta.contentHash,
  source_path: meta.filePath,
  source_filename: meta.fileName,
  source_mime: meta.mime,
  source_size_bytes: 0,
  event_id: meta.eventId
};
return msg;

// Ledger job created (or 409 if exists). Restore msg for MinIO upload.
const meta = msg.meta || {};
node.warn('[ingest] Ledger job created/exists for ' + (meta.contentHash || '').slice(0,12));
msg.execArgs = '"' + meta.filePath + '" "' + meta.objectKey + '"';
msg.filename = meta.filePath;
msg._ledgerHash = meta.contentHash;
// PATCH ledger to uploading status
msg._nextPayload = {
  execArgs: msg.execArgs,
  filename: msg.filename
};
msg.headers = { 'content-type': 'application/json' };
msg.url = 'http://localhost:18697/jobs/' + encodeURIComponent(meta.contentHash);
msg.payload = { status: 'uploading' };
return msg;

const resp = msg.payload || {};
const data = resp.data || {};
const upload = data.uploadAudio || {};
const contentHash = msg._contentHash;

if (!upload.success) {
  node.warn('[upload] Fireflies upload failed: ' + (upload.message || 'unknown'));
  // Send error to second output for error PATCH
  if (contentHash) {
    const errMsg = {
      headers: { 'content-type': 'application/json' },
      url: 'http://localhost:18697/jobs/' + encodeURIComponent(contentHash),
      payload: {
        status: 'failed',
        error_message: 'Fireflies uploadAudio failed: ' + (upload.message || 'unknown'),
        error_stage: 'transcribing'
      }
    };
    return [null, errMsg];
  }
  return [null, null];
}

if (!contentHash) {
  node.warn('[upload] Fireflies upload succeeded but no content_hash available for ledger');
  return [null, null];
}

node.warn('[upload] Fireflies upload succeeded, updating ledger for ' + contentHash.slice(0,12));
msg.headers = { 'content-type': 'application/json' };
msg.url = 'http://localhost:18697/jobs/' + encodeURIComponent(contentHash);
msg.payload = {
  status: 'transcribing',
  fireflies_ref: upload.title || null
};
return [msg, null];

// Restore msg fields for MinIO upload after ledger PATCH
const meta = msg.meta || {};
msg.execArgs = '"' + meta.filePath + '" "' + meta.objectKey + '"';
msg.filename = meta.filePath;
return msg;

// PATCH ledger with uploaded status and MinIO details
const meta = msg.meta || {};
const presign = msg.payload || {};
// Save presign data for later
msg._presignData = presign;
msg.headers = { 'content-type': 'application/json' };
msg.url = 'http://localhost:18697/jobs/' + encodeURIComponent(meta.contentHash);
const bucket = (presign.bucket || (env.get('MINIO_BUCKET') || 'echobox'));
const key = meta.objectKey || presign.key || '';
msg.payload = {
  status: 'uploaded',
  minio_bucket: bucket,
  minio_key: key,
  minio_url: presign.url || ''
};
return msg;

// Restore presign data after ledger PATCH
msg.payload = msg._presignData || {};
return msg;

// PATCH ledger with failed status on MinIO error
const meta = msg.meta || {};
const errMsg = (msg.payload || '').toString().slice(0, 500);
msg.headers = { 'content-type': 'application/json' };
msg.url = 'http://localhost:18697/jobs/' + encodeURIComponent(meta.contentHash || 'unknown');
msg.payload = {
  status: 'failed',
  error_message: 'MinIO upload failed: ' + errMsg,
  error_stage: 'uploading'
};
return msg;

// PATCH ledger with failed status on publish error
const meta = msg.meta || {};
const errMsg = (msg.payload || '').toString().slice(0, 500);
msg.headers = { 'content-type': 'application/json' };
msg.url = 'http://localhost:18697/jobs/' + encodeURIComponent(meta.contentHash || 'unknown');
msg.payload = {
  status: 'failed',
  error_message: 'Bloodbank publish failed: ' + errMsg,
  error_stage: 'uploaded'
};
return msg;

// PATCH ledger to ready status after transcript fetched
const meta = msg.meta || {};
const contentHash = meta.contentHash;
const response = msg.payload || {};
const transcript = response.data && response.data.transcript;

if (!transcript) {
  node.error('Transcript not found in response', msg);
  // Try to PATCH failed if we have content_hash
  if (contentHash) {
    msg.headers = { 'content-type': 'application/json' };
    msg.url = 'http://localhost:18697/jobs/' + encodeURIComponent(contentHash);
    msg.payload = {
      status: 'failed',
      error_message: 'Transcript not found in Fireflies API response',
      error_stage: 'ready'
    };
    return [null, msg];
  }
  return [null, null];
}

// Save response for later
msg._transcriptResponse = response;

if (!contentHash) {
  node.warn('[webhook] No content_hash available, skipping ledger ready PATCH');
  msg.payload = response;
  return [msg, null];
}

msg.headers = { 'content-type': 'application/json' };
msg.url = 'http://localhost:18697/jobs/' + encodeURIComponent(contentHash);
msg.payload = {
  status: 'ready',
  fireflies_id: transcript.id
};
return [msg, null];

// Restore transcript response after ledger PATCH
msg.payload = msg._transcriptResponse || {};
return msg;
